const PHASE_STYLE = {
  'New Material': { label: 'New Waters', color: '#d4a24e' },
  'Recovery': { label: 'Anchored', color: '#5b7a8c' },
  'Phase 1: Spaced Repetition': { label: 'First Tide', color: '#8a6fb0' },
  'Phase 2: Spaced Repetition': { label: 'Second Tide', color: '#6f8ab0' },
  'Phase 3: Grand Revision': { label: 'Final Approach', color: '#c1583f' },
  'University Exams': { label: 'Storm (Exams)', color: '#8c2f2f' },
};

function monthKey(dateStr) {
  const [y, m] = dateStr.split('-');
  return `${y}-${m}`;
}
function monthLabel(key) {
  const [y, m] = key.split('-');
  return new Date(Number(y), Number(m) - 1, 1).toLocaleString('en-US', { month: 'long', year: 'numeric' });
}

export default function StudyTracker() {
  const [done, setDone] = useState({});
  const [loaded, setLoaded] = useState(false);
  const [openMonths, setOpenMonths] = useState({});
  const [query, setQuery] = useState('');
  const [subjectFilter, setSubjectFilter] = useState('All');
  const [error, setError] = useState(null);

  useEffect(() => {
    (async () => {
      try {
        const res = await window.storage.get('done-map', false);
        if (res && res.value) setDone(JSON.parse(res.value));
      } catch (e) { /* no data yet */ }
      setLoaded(true);
    })();
  }, []);

  useEffect(() => {
    if (!loaded) return;
    (async () => {
      try {
        await window.storage.set('done-map', JSON.stringify(done), false);
      } catch (e) { setError('Could not save progress.'); }
    })();
  }, [done, loaded]);

  const months = useMemo(() => {
    const map = {};
    SCHEDULE.forEach((row, idx) => {
      const k = monthKey(row.Date);
      if (!map[k]) map[k] = [];
      map[k].push({ ...row, idx });
    });
    return Object.entries(map).sort((a, b) => a[0].localeCompare(b[0]));
  }, []);

  const subjects = useMemo(() => {
    const s = new Set();
    SCHEDULE.forEach(r => { if (r['Subject / Focus'] && r['Subject / Focus'] !== '-') s.add(r['Subject / Focus']); });
    return ['All', ...Array.from(s).sort()];
  }, []);

  const totalTopics = useMemo(() => SCHEDULE.filter(r => r.Phase !== 'Recovery' && r.Phase !== 'University Exams').length, []);
  const doneCount = useMemo(() => Object.values(done).filter(Boolean).length, [done]);
  const pct = totalTopics ? Math.round((doneCount / totalTopics) * 100) : 0;

  const todayStr = new Date().toISOString().slice(0, 10);

  function toggleMonth(k) {
    setOpenMonths(prev => ({ ...prev, [k]: !prev[k] }));
  }
  function toggleDone(idx) {
    setDone(prev => ({ ...prev, [idx]: !prev[idx] }));
  }

  function matchesFilter(row) {
    if (subjectFilter !== 'All' && row['Subject / Focus'] !== subjectFilter) return false;
    if (query.trim()) {
      const q = query.toLowerCase();
      const hay = `${row['Tasks / Topics']} ${row['Subject / Focus']} ${row.Notes}`.toLowerCase();
      if (!hay.includes(q)) return false;
    }
    return true;
  }

  // auto-open the month containing today, once
  useEffect(() => {
    const k = monthKey(todayStr);
    setOpenMonths(prev => (Object.keys(prev).length ? prev : { [k]: true }));
  }, []);

  return (
    <div style={styles.page}>
      <div style={styles.grain} />
      <header style={styles.header}>
        <div style={styles.headerTop}>
          <Compass size={22} color="#d4a24e" style={{ flexShrink: 0 }} />
          <div>
            <div style={styles.eyebrow}>SHIP'S LOG — MBBS GRAND FINALE</div>
            <h1 style={styles.title}>Course to September 2027</h1>
          </div>
        </div>
        <div style={styles.progressRow}>
          <div style={styles.progressBarOuter}>
            <div style={{ ...styles.progressBarInner, width: `${pct}%` }} />
          </div>
          <span style={styles.progressText}>{doneCount} / {totalTopics} legs charted · {pct}%</span>
        </div>
      </header>

      <div style={styles.controls}>
        <div style={styles.searchBox}>
          <Search size={15} color="#8a7f6a" />
          <input
            style={styles.searchInput}
            placeholder="Search topics, notes..."
            value={query}
            onChange={e => setQuery(e.target.value)}
          />
        </div>
        <select style={styles.select} value={subjectFilter} onChange={e => setSubjectFilter(e.target.value)}>
          {subjects.map(s => <option key={s} value={s}>{s}</option>)}
        </select>
      </div>

      {error && <div style={styles.errorBox}>{error}</div>}

      <main style={styles.main}>
        {months.map(([mKey, rows]) => {
          const visibleRows = rows.filter(matchesFilter);
          if (visibleRows.length === 0) return null;
          const isOpen = !!openMonths[mKey];
          const isExamMonth = rows.some(r => r.Phase === 'University Exams');
          const monthDone = rows.filter(r => done[r.idx] && r.Phase !== 'Recovery' && r.Phase !== 'University Exams').length;
          const monthTotal = rows.filter(r => r.Phase !== 'Recovery' && r.Phase !== 'University Exams').length;
          return (
            <section key={mKey} style={styles.monthSection}>
              <button style={styles.monthHeader} onClick={() => toggleMonth(mKey)}>
                {isOpen ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
                <span style={styles.monthLabel}>{monthLabel(mKey)}</span>
                {isExamMonth && <span style={styles.examBadge}><Flag size={11} style={{ marginRight: 4 }} />Exam month</span>}
                <span style={styles.monthCount}>{monthTotal > 0 ? `${monthDone}/${monthTotal}` : ''}</span>
              </button>
              {isOpen && (
                <div style={styles.dayList}>
                  {visibleRows.map(row => {
                    const isRest = row.Phase === 'Recovery' || row['Subject / Focus'] === '-';
                    const isExam = row.Phase === 'University Exams';
                    const isToday = row.Date === todayStr;
                    const style = PHASE_STYLE[row.Phase] || { label: row.Phase, color: '#999' };
                    return (
                      <div key={row.idx} style={{
                        ...styles.dayRow,
                        ...(isToday ? styles.dayRowToday : {}),
                        ...(isRest || isExam ? styles.dayRowMuted : {}),
                      }}>
                        <button
                          style={styles.checkbox}
                          onClick={() => !isRest && !isExam && toggleDone(row.idx)}
                          disabled={isRest || isExam}
                        >
                          {done[row.idx] && <Check size={13} color="#1a1712" strokeWidth={3} />}
                        </button>
                        <div style={styles.dateCol}>
                          <div style={styles.dateNum}>{row.Date.slice(8, 10)}</div>
                          <div style={styles.dateDow}>{row.Day.slice(0, 3)}</div>
                        </div>
                        <div style={styles.contentCol}>
                          <div style={styles.rowTopLine}>
                            <span style={{ ...styles.phaseTag, color: style.color, borderColor: style.color }}>{style.label}</span>
                            {!isRest && !isExam && <span style={styles.subjectText}>{row['Subject / Focus']}</span>}
                          </div>
                          <div style={{
                            ...styles.taskText,
                            ...(done[row.idx] ? styles.taskTextDone : {}),
                          }}>
                            {row['Tasks / Topics']}
                          </div>
                          {row.Notes && <div style={styles.notesText}>{row.Notes}</div>}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </section>
          );
        })}
      </main>

      <footer style={styles.footer}>
        <Anchor size={13} color="#5b7a8c" />
        <span>Progress saved automatically on this device.</span>
      </footer>
    </div>
  );
}

